const cp = require('child_process');
const fs = require('fs');
const input = $input.first().json;
const project = (input.params && input.params.project) || input.project || '';

if (!project) {
  return [{json: {status: 'error', error: 'Missing project path. Use: params.project=/path/to/project'}}];
}

// Path traversal protection: must be a real agent project
if (!fs.existsSync(project + '/.template-manifest.json') && !fs.existsSync(project + '/CLAUDE.md')) {
  return [{json: {status: 'error', error: 'Not an agent project (no .template-manifest.json or CLAUDE.md): ' + project}}];
}

try {
  const result = cp.execSync('bash scripts/sync-template.sh --from-git 2>&1', {cwd: project, timeout: 60000, encoding: 'utf8'});
  const updated = (result.match(/UPDATED:\s+(\d+)/) || [,'0'])[1];
  const newFiles = (result.match(/NEW:\s+(\d+)/) || [,'0'])[1];
  const conflicts = (result.match(/CONFLICT/g) || []).length;

  return [{json: {
    status: 'complete', project,
    updated: parseInt(updated), new_files: parseInt(newFiles), conflicts,
    full_output: result, timestamp: new Date().toISOString()
  }}];
} catch(e) {
  return [{json: {status: 'error', project, error: (e.stdout || '') + (e.stderr || e.message)}}];
}
